from itertools import combinations
class Solution:
    def putMarbles(self, weights, k):
        n = len(weights)
        if k == n:
            return 0
        gaps = list(range(n - 1))
        best_max = None
        best_min = None
        for cuts in combinations(gaps, k - 1):
            cost = weights[0] + weights[-1]
            for c in cuts:
                cost += weights[c] + weights[c + 1]
            if best_max is None or cost > best_max:
                best_max = cost
            if best_min is None or cost < best_min:
                best_min = cost
        return best_max - best_min

