class Solution:
    def putMarbles(self, weights, k):
        n = len(weights)
        if k == 1 or k == n:
            return 0
        pair_sums = sorted(weights[i] + weights[i + 1] for i in range(n - 1))
        m = k - 1
        return sum(pair_sums[-m:]) - sum(pair_sums[:m])

